// Aggregate today's leads: count by urgency, count by product, top 5 most recent.
const rows = $input.all().map(i => i.json);
const today = new Date().toISOString().slice(0, 10);

const todays = rows.filter(r => String(r.received_at || '').slice(0, 10) === today);

const byUrgency = {};
const byProduct = {};
for (const r of todays) {
  const u = String(r.urgency || 'unknown').toLowerCase();
  byUrgency[u] = (byUrgency[u] || 0) + 1;
  const p = String(r.product || 'unknown');
  byProduct[p] = (byProduct[p] || 0) + 1;
}

const top5 = [...todays]
  .sort((a, b) => String(b.received_at).localeCompare(String(a.received_at)))
  .slice(0, 5)
  .map(r => ({ name: r.name, company: r.company, product: r.product, urgency: r.urgency, received_at: r.received_at }));

return [{
  json: {
    date: today,
    total_today: todays.length,
    by_urgency: byUrgency,
    by_product: byProduct,
    top5_recent: top5
  }
}];

// Format the digest into Slack Block Kit JSON.
const d = $json;
const urgencyLines = Object.entries(d.by_urgency).map(([k, v]) => `• ${k}: *${v}*`).join('\n') || '_none_';
const productLines = Object.entries(d.by_product).map(([k, v]) => `• ${k}: *${v}*`).join('\n') || '_none_';
const top5Lines = d.top5_recent.length
  ? d.top5_recent.map((r, i) => `${i + 1}. *${r.name}* (${r.company}) — ${r.product} [${r.urgency}]`).join('\n')
  : '_no leads today_';

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: `📊 Daily Lead Digest — ${d.date}`, emoji: true } },
  { type: 'section', text: { type: 'mrkdwn', text: `*Total leads today:* ${d.total_today}` } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: `*By urgency:*\n${urgencyLines}` },
    { type: 'mrkdwn', text: `*By product:*\n${productLines}` }
  ] },
  { type: 'section', text: { type: 'mrkdwn', text: `*Top 5 recent:*\n${top5Lines}` } }
];

return [{ json: { blocks_json: JSON.stringify({ blocks }) } }];
